import React from 'react';
import styled, { keyframes } from 'styled-components';
import { useNavigate } from 'react-router-dom';
import { 
  Sparkles, 
  Bot, 
  Code, 
  Database, 
  Cloud, 
  Rocket, 
  Zap, 
  Globe, 
  Smartphone, 
  ShoppingCart, 
  BarChart3, 
  MessageSquare,
  GitBranch,
  Server,
  HardDrive,
  MousePointerClick,
  Lightbulb,
  Wand2
} from 'lucide-react';

const float = keyframes`
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-20px); }
`;

const pulse = keyframes`
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
`;

const gradient = keyframes`
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
`;

const Container = styled.div`
  min-height: 100vh;
  background: linear-gradient(135deg, #f0f4f8 0%, #e6f7ff 100%);
`;

const HeroSection = styled.section`
  padding: 5rem 2rem;
  text-align: center;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  position: relative;
  overflow: hidden;
  
  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: radial-gradient(circle at center, rgba(255,255,255,0.1) 0%, rgba(255,255,255,0) 70%);
  }
`;

const HeroContent = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  position: relative;
  z-index: 2;
`;

const Title = styled.h1`
  font-size: 3.5rem;
  font-weight: 800;
  margin-bottom: 1.5rem;
  background: linear-gradient(45deg, #fff, #e2e8f0);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  
  @media (max-width: 768px) {
    font-size: 2.5rem;
  }
`;

const Subtitle = styled.p`
  font-size: 1.5rem;
  opacity: 0.9;
  max-width: 700px;
  margin: 0 auto 2rem;
  
  @media (max-width: 768px) {
    font-size: 1.2rem;
  }
`;

const CTAButton = styled.button`
  background: white;
  color: #667eea;
  border: none;
  padding: 1.25rem 2.5rem;
  font-size: 1.25rem;
  font-weight: 600;
  border-radius: 3rem;
  cursor: pointer;
  transition: all 0.3s ease;
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.2);
  
  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 15px 35px rgba(0, 0, 0, 0.3);
  }
`;

const FeaturesSection = styled.section`
  padding: 5rem 2rem;
  max-width: 1400px;
  margin: 0 auto;
`;

const SectionTitle = styled.h2`
  text-align: center;
  font-size: 2.5rem;
  font-weight: 700;
  color: #1e293b;
  margin-bottom: 3rem;
`;

const FeaturesGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
`;

const FeatureCard = styled.div`
  background: white;
  border-radius: 1.5rem;
  padding: 2rem;
  text-align: center;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  transition: all 0.3s ease;
  border: 1px solid #e2e8f0;
  
  &:hover {
    transform: translateY(-10px);
    box-shadow: 0 15px 40px rgba(102, 126, 234, 0.15);
  }
`;

const FeatureIcon = styled.div`
  width: 5rem;
  height: 5rem;
  border-radius: 1.5rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  margin: 0 auto 1.5rem;
  font-size: 2rem;
  animation: ${float} 3s ease-in-out infinite;
`;

const FeatureTitle = styled.h3`
  font-size: 1.5rem;
  font-weight: 600;
  color: #1e293b;
  margin-bottom: 1rem;
`;

const FeatureDescription = styled.p`
  color: #64748b;
  font-size: 1.1rem;
  line-height: 1.6;
`;

const StatsSection = styled.section`
  padding: 5rem 2rem;
  background: linear-gradient(135deg, #1e293b 0%, #0f172a 100%);
  color: white;
  text-align: center;
`;

const StatsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 2rem;
  max-width: 1200px;
  margin: 0 auto;
`;

const StatItem = styled.div`
  padding: 2rem;
`;

const StatNumber = styled.div`
  font-size: 3rem;
  font-weight: 700;
  margin-bottom: 1rem;
  background: linear-gradient(45deg, #667eea, #764ba2);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
`;

const StatLabel = styled.div`
  font-size: 1.25rem;
  opacity: 0.8;
`;

const CTASection = styled.section`
  padding: 5rem 2rem;
  text-align: center;
  background: linear-gradient(45deg, #667eea 0%, #764ba2 100%);
  color: white;
`;

const CTAContent = styled.div`
  max-width: 800px;
  margin: 0 auto;
`;

const CTATitle = styled.h2`
  font-size: 2.5rem;
  font-weight: 700;
  margin-bottom: 1.5rem;
`;

const CTADescription = styled.p`
  font-size: 1.25rem;
  opacity: 0.9;
  margin-bottom: 2rem;
`;

function Home() {
  const navigate = useNavigate();
  
  const features = [
    {
      icon: <Wand2 size={32} />,
      title: "AI-Powered Builder",
      description: "Create stunning applications with our intelligent AI builder that understands your requirements and generates production-ready code."
    },
    {
      icon: <Bot size={32} />,
      title: "AI Chat Assistant",
      description: "Get instant help with coding, debugging, and optimization from our AI-powered coding assistant."
    },
    {
      icon: <Code size={32} />,
      title: "Multi-Framework Support",
      description: "Build applications using React, Vue, Angular, Node.js, Python, and more with our flexible framework support."
    },
    {
      icon: <Rocket size={32} />,
      title: "One-Click Deployment",
      description: "Deploy your applications to AWS, Google Cloud, Azure, or Vercel with a single click."
    },
    {
      icon: <Database size={32} />,
      title: "Database Integration",
      description: "Seamlessly integrate with MySQL, PostgreSQL, MongoDB, and other databases."
    },
    {
      icon: <Globe size={32} />,
      title: "Responsive Design",
      description: "Create beautiful, responsive applications that work perfectly on all devices."
    }
  ];
  
  const stats = [
    { number: "10K+", label: "Applications Built" },
    { number: "99.9%", label: "Uptime" },
    { number: "500+", label: "Supported Frameworks" },
    { number: "24/7", label: "AI Support" }
  ];
  
  return (
    <Container>
      <HeroSection>
        <HeroContent>
          <Title>Build Amazing Applications with AI</Title>
          <Subtitle>
            Create, deploy, and scale your applications faster than ever with our AI-powered development platform
          </Subtitle>
          <CTAButton onClick={() => navigate('/builder')}>
            Start Building Now
          </CTAButton>
        </HeroContent>
      </HeroSection>
      
      <FeaturesSection>
        <SectionTitle>Powerful Features</SectionTitle>
        <FeaturesGrid>
          {features.map((feature, index) => (
            <FeatureCard key={index}>
              <FeatureIcon>
                {feature.icon}
              </FeatureIcon>
              <FeatureTitle>{feature.title}</FeatureTitle>
              <FeatureDescription>{feature.description}</FeatureDescription>
            </FeatureCard>
          ))}
        </FeaturesGrid>
      </FeaturesSection>
      
      <StatsSection>
        <StatsGrid>
          {stats.map((stat, index) => (
            <StatItem key={index}>
              <StatNumber>{stat.number}</StatNumber>
              <StatLabel>{stat.label}</StatLabel>
            </StatItem>
          ))}
        </StatsGrid>
      </StatsSection>
      
      <CTASection>
        <CTAContent>
          <CTATitle>Ready to Build Your Next Application?</CTATitle>
          <CTADescription>
            Join thousands of developers who are already creating amazing applications with our platform
          </CTADescription>
          <CTAButton onClick={() => navigate('/builder')}>
            Get Started Free
          </CTAButton>
        </CTAContent>
      </CTASection>
    </Container>
  );
}

export default Home;
